def solve_with_react(question):
    thought = llm(f'Think step-by-step for: {question}')
    action = llm(f'Choose tool call from thought:\n{thought}')
    obs = call_tool(action)
    thought2 = llm(f'Observation: {obs}\nUpdate reasoning.')
    return llm(f'Final answer from reasoning:\n{thought2}')

